def make_proven_verdict(text: str, premise_ids, b: 'CardBundle') -> 'ProvenVerdict | None':
    """THE ONLY DOOR to a `ProvenVerdict`. The deterministic planner hands us a canonical verdict string;
    we classify the operation its claim licenses, build the frozen proof-carrying node, and RE-GATE it
    through the full validator. Anything that does not classify, has fewer than two premises, or fails
    revalidation returns `None` — a verdict that cannot be proved is not placed."""
    if len(premise_ids) < 2:
        return None
    from synthesis_contract import classify_claim as _cc  # noqa: PLC0415
    t = (text or '').strip()
    if not t:
        return None
    _claim, op = _cc(t)
    if not op:
        return None
    node = ProvenVerdict(text=t, premise_ids=tuple(premise_ids), operation=op)
    return node if not validate_report([node], b) else None

